import { PillNav } from '@/sd-components/386926b7-61c2-45ee-b7bf-f86e750ca9ca';

const MyNav = () => {
  const items = [
    { label: 'Home', href: '/' },
    { label: 'Products', href: '/products' },
    { label: 'About', href: '/about' }
  ];

  return (
    <PillNav 
      logo="/logo.svg"
      items={items}
      activeHref="/"
    />
  );
};
