{
  "summary": "A sophisticated monochrome wireframe design system for e-commerce, focusing on clean structure, neutral gray scales, and precise typography to showcase product collections without visual noise.",
  "style": {
    "description": "The style is defined by a high-contrast grayscale palette and a 'General Sans' sans-serif typeface. It utilizes wide gutters, subtle borders (#E5E7EB), and micro-interactions like text-decoration transitions. The aesthetic prioritizes negative space and structural clarity over decorative elements.",
    "prompt": "Apply a minimalist monochrome design system. Typography: Use 'General Sans' or a similar clean sans-serif. Headings: 36px (text-4xl) with font-weight 600 and -0.025em letter-spacing. Body: 14px (text-sm) font-weight 400. Color Palette: Primary Background #FFFFFF, Primary Text #111827, Secondary Text #6B7280, Border/Dividers #E5E7EB, Light Backgrounds #F9FAFB. Spacing: Base unit 4px; use 32px (8 units) for section gaps and 48px (12 units) for collection headers. Animations: Use 'cubic-bezier(0.4, 0, 0.2, 1)' for hover transitions. Borders: 1px solid throughout. Shadows: None; use borders for definition."
  },
  "layout_and_structure": {
    "description": "A classic e-commerce collection layout with a sticky header, a wide sidebar for desktop filtering, and a flexible grid system that transitions from 1 column (mobile) to 3 columns (desktop).",
    "prompts": [
      {
        "part": "Header",
        "prompt": "Create a 64px height sticky header with #FFFFFF background and 95% opacity backdrop-blur. Include a 24x6 logo placeholder, a centered desktop nav with 32px spacing (text-sm, medium weight), and a right-aligned icon group (search, user, shopping bag). Search bar should be a 256px wide rounded-sm box in #F3F4F6."
      },
      {
        "part": "Collection Header",
        "prompt": "Position a breadcrumb trail at the top using 12px text. Below, place a 36px (text-4xl) font-weight 600 title. Follow with a description paragraph (max-width 512px) in #6B7280 with 1.625 line-height. Add 48px bottom margin before the main content grid."
      },
      {
        "part": "Sidebar Filters",
        "prompt": "Desktop-only 256px sidebar. Structure into sections: 1. Category (Checkboxes with 16px squares and #E5E7EB borders), 2. Size (3-column grid of 40px squares with centered 12px text), 3. Color (24px circles with 2px ring-offsets). Use 1px borders for group dividers."
      },
      {
        "part": "Product Grid",
        "prompt": "Main grid area with 3-column layout (xl screens) and 24px column gaps. Each card features a 3:4 aspect ratio image placeholder in #F3F4F6. Product title below image in 14px medium weight text, price in #6B7280. Include a hover state: product title gains 'underline decoration-1 underline-offset-4'."
      },
      {
        "part": "Pagination",
        "prompt": "Bottom pagination section with a top-border in #F3F4F6. Include 'Previous' and 'Next' text buttons with arrow icons. Center a numeric list where the active page is a 32px #111827 square with white text, and inactive pages are 32px squares with #6B7280 text."
      }
    ]
  },
  "special_ui_components": [
    {
      "component": "Product Status Badge",
      "description": "Small informational labels positioned over product images.",
      "prompt": "Create a 10px font-size badge with bold tracking-wider uppercase text. New Arrivals: #FFFFFF background with 1px #E5E7EB border. Sold Out: #111827 background with #FFFFFF text. Position absolute at top-3 left-3 with 4px/8px padding."
    },
    {
      "component": "Size Selector Grid",
      "description": "Interactive grid for quick size selection.",
      "prompt": "A grid of 1x1 aspect ratio boxes. Default state: 1px border #E5E7EB, #6B7280 text. Hover state: 1px border #111827. Transition duration 150ms."
    }
  ],
  "special_notes": "Must-do: Maintain exact 3:4 aspect ratio for all product image containers to preserve the editorial feel. Must-do: Use #F3F4F6 for all placeholder elements to distinguish from white background. Must-not: Use any shadows or rounded corners larger than 2px. Must-not: Use saturated colors; even the 'Color' filters should remain neutral unless specific brand colors are required."
}

{
  "summary": "A sophisticated, mobile-first product browsing layout emphasizing whitespace, clean typography, and a stable 2-column grid. The design utilizes a monochrome base with slate-toned neutrals to create a high-end 'boutique' feel, prioritizing product imagery and effortless navigation.",
  "style": {
    "description": "Minimalist editorial style using 'General Sans' for a modern feel. The palette is dominated by pure white (#FFFFFF), slate grays (#F1F5F9, #64748B, #0F172A), and sharp black accents. Animations are subtle, featuring 700ms image transitions and 95% scaling on active touch states. Borders are thin (1px) and used sparingly to define hierarchy without clutter.",
    "prompt": "Create a design with a 'Minimalist Editorial' aesthetic. \n- **Typography**: Primary font 'General Sans'. Use font-weight 600 for headings (24px, -0.025em tracking) and product titles (14px). Use font-weight 400 for categories (12px, #64748B).\n- **Color Palette**: Backgrounds in #FFFFFF; Secondary surfaces in #F8FAFC; Borders in #F1F5F9; Primary text in #0F172A; Accents in #000000.\n- **Shadows & Borders**: Avoid heavy shadows. Use 1px solid borders in #F1F5F9 for headers, footers, and pills.\n- **Interactions**: Implement a `duration-700` ease-out transition on image hover (scale: 105%). Use `active:scale-95` for all clickable buttons and pills for tactile feedback.\n- **Radius**: Large radius (9999px) for category pills and circular icon buttons; sharp corners (0px) for product images to maintain a professional look."
  },
  "layout_and_structure": {
    "description": "A vertical-scrolling mobile layout composed of a sticky header, a scrollable category filter, a fixed-width grid, and a persistent bottom navigation bar.",
    "prompts": [
      {
        "part": "Header and Category Bar",
        "prompt": "Design a sticky top header with 56px top padding (safe area). Include a title 'Collection' at 24px semi-bold left-aligned, and two 40px circular action buttons (Search, Filter) on the right. Below the title, add a horizontally scrollable (hide-scrollbar) container of category pills. Active pill: Black background, White text. Inactive pill: #F8FAFC background, 1px #F1F5F9 border, #64748B text. All pills should have 10px 20px padding and text-sm font-weight 500."
      },
      {
        "part": "Product Grid",
        "prompt": "Construct a 2-column grid with a 16px (gap-4) horizontal gap and 32px (gap-8) vertical gap. Each card should contain a 3:4 aspect ratio image container. Images must use `object-cover`. On hover, images scale 5%. Cards must have a title (text-sm, truncated) and price (text-xs, font-medium) on one line, with a secondary category label (#64748B, text-xs) below."
      },
      {
        "part": "Bottom Navigation",
        "prompt": "Fixed bottom bar at 100% width, #FFFFFF background with a 1px top border (#F1F5F9). Height should accommodate safe area (pb-[34px]). Include 4 equally spaced navigation items consisting of a 20px icon and a 10px font-weight 500 label. Active state: #000000; Inactive state: #94A3B8."
      }
    ]
  },
  "special_ui_components": [
    {
      "component": "Interactive Filter Button",
      "description": "Action icon with a status indicator",
      "prompt": "A 40px circular button with a 'sliders-horizontal' icon. Add a 8px solid black dot (#000000) positioned at top: 10px, right: 10px to indicate active filters."
    },
    {
      "component": "Status Badges",
      "description": "Minimalist overlay labels on images",
      "prompt": "Small rectangular badges positioned top-left of the image container. Text: 10px uppercase bold. 'NEW' badge: Black background/White text. 'SALE' badge: Red background (#EF4444)/White text. Padding: 4px 8px."
    }
  ],
  "special_notes": "MUST: Maintain strict 3:4 aspect ratios for product images. MUST: Use 'General Sans' or a very clean geometric sans-serif to maintain the high-end feel. DO NOT: Use heavy drop shadows or rounded corners on images. DO NOT: Allow the header to obscure content without a backdrop-blur effect (bg-white/95 backdrop-blur-sm)."
}

{
  "summary": "A luxe, trustworthy mobile subscription / premium-upgrade PAYWALL on near-black with champagne-gold accents: a brand + 'PRO' lockup with a close button, an editorial italic-serif value headline + subhead, a Free-vs-Pro feature comparison table with gold checks, two plan cards (Yearly with a 'Best value / save %' badge + selected state, and Monthly), a prominent gold 'Start free trial' CTA, a trust line, and small legal/restore footer links. Reads premium, not pushy.",
